"""Pricing engine — calculates discounts and tax."""

# Discount codes and their percentage values
DISCOUNT_CODES = {
    "SAVE10": 10,
    "SAVE20": 20,
    "HALF": 50,
    "VIP": 30,
}

TAX_RATE = 0.08  # 8% sales tax


def get_discount_multiplier(code):
    """Return the multiplier to apply for a discount code.

    Example: 20% discount -> multiplier of 0.8
    No discount -> multiplier of 1.0
    """
    if not code or code not in DISCOUNT_CODES:
        return 1.0
    percentage = DISCOUNT_CODES[code]
    return 1.0 + (percentage / 100)  # BUG: should be 1.0 - (percentage / 100)


def calculate_tax(subtotal):
    """Calculate tax on a subtotal."""
    return round(subtotal * TAX_RATE, 2)


def format_currency(amount):
    """Format a number as currency string."""
    return f"${amount:.2f}"
